   1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
   2→import { Stage } from 'react-konva';
   3→import { useNavigate, useLocation } from 'react-router-dom';
   4→import { useAuth } from '../../Context/useAuth';
   5→import { getUniversePosts, getUserData, getViewportConstellations } from '../../../API/Api';
   6→import supabase from '../../utils/supabaseClient';
   7→import useUniverseCamera from './hooks/useUniverseCamera';
   8→import useCosmicGravity from './hooks/useCosmicGravity';
   9→import useConstellationLinkMode from './hooks/useConstellationLinkMode';
  10→
  11→import DeepSpaceLayer from './layers/DeepSpaceLayer';
  12→import MidGalaxyLayer from './layers/MidGalaxyLayer';
  13→import NebulaLayer from './layers/NebulaLayer';
  14→import InteractiveLayer from './layers/InteractiveLayer';
  15→import WormholeLayer from './layers/WormholeLayer';
  16→import ConstellationLayer from './layers/ConstellationLayer';
  17→import RocketLayer from './layers/RocketLayer';
  18→import UniverseMinimap from './components/UniverseMinimap';
  19→import RocketHUD from './components/RocketHUD';
  20→import useRocketMode, { MAGNET_THRESHOLD_Z } from './hooks/useRocketMode';
  21→import { extractSnippet, MIN_UNIVERSE_ZOOM, userHomeCoords } from './utils/starUtils';
  22→import {
  23→    buildSectorIndex,
  24→    computeGalaxyCentroids,
  25→    computeConstellationPullOffsets,
  26→    computeSectorKey,
  27→    getNeighborSectorKeys,
  28→} from './utils/cosmicPhysics';
  29→import { computeConstellationChains, assignChainColors } from './utils/constellationUtils';
  30→import { handleClickProfile } from '../../../helpers/handleClicks';
  31→import styles from './Universe.module.css';
  32→
  33→const SECTOR_SIZE = 2000;
  34→const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';
  35→
  36→const Universe = () => {
  37→    const navigate = useNavigate();
  38→    const location = useLocation();
  39→    const { user, session } = useAuth();
  40→    const userId = user?.userData?.[0]?.id || null;
  41→
  42→    const fetchDebounceRef = useRef(null);
  43→    const settleDebounceRef = useRef(null);
  44→    const lastSettledPayloadRef = useRef('');
  45→    const initialFetchResolvedRef = useRef(false);
  46→    const hasAutoFocusedOwnGalaxyRef = useRef(false);
  47→    const ownGalaxyLookupStartedRef = useRef(false);
  48→    const constellationFlyToRef = useRef(location.state?.flyToConstellation || null);
  49→
  50→    const [posts, setPosts] = useState(new Map());
  51→    const [selectedPost, setSelectedPost] = useState(null);
  52→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
  53→    const [galaxyProfile, setGalaxyProfile] = useState(null);
  54→    const [pulsingId, setPulsingId] = useState(null);
  55→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
  56→    const [isInitialLoading, setIsInitialLoading] = useState(true);
  57→    const [ownGalaxyTarget, setOwnGalaxyTarget] = useState(null);
  58→    const [wormholes, setWormholes] = useState([]);
  59→    const [isWarping, setIsWarping] = useState(false);
  60→    const [constellations, setConstellations] = useState([]);
  61→    const [linkModeError, setLinkModeError] = useState(null);
  62→    const [focusedConstellation, setFocusedConstellation] = useState(null);
  63→    const [universeMode, setUniverseMode] = useState('strategic');
  64→    const [rocketWarpIn, setRocketWarpIn] = useState(false);
  65→    const [reverseWarpActive, setReverseWarpActive] = useState(false);
  66→    const selectedGalaxyUserIdRef = useRef(null);
  67→    const pendingRocketRestoreRef = useRef(null);
  68→    const warpTimerRef = useRef(null);
  69→
  70→    // Gravity data from server (fallback paths when embeddings are unavailable in payload)
  71→    const [centroids, setCentroids] = useState([]);
  72→    const [galaxyEdges, setGalaxyEdges] = useState([]);
  73→    const [similarPairs, setSimilarPairs] = useState([]);
  74→    const [starPulls, setStarPulls] = useState([]);
  75→
  76→    // Shared ref: prevents camera pan while dragging a star
  77→    const isStarDragging = useRef(false);
  78→
  79→    const {
  80→        stageRef, stageSize, camera, zoom, isDragging, centerWorld,
  81→        getLayerProps, getViewportBounds, stageEvents, flyTo, jumpTo, isFlying,
  82→    } = useUniverseCamera(userId, hasOwnPosts, isStarDragging);
  83→
  84→    const {
  85→        isLinkMode, firstStar, secondStar, isSubmitting, linkModeStatus,
  86→        toggleLinkMode, cancelLinkMode, handleStarClickInLinkMode, submitLink,
  87→    } = useConstellationLinkMode(userId, session);
  88→
  89→    const rocketMode = useRocketMode();
  90→
  91→    const [labelInput, setLabelInput] = useState('');
  92→
  93→    const focusedStarIds = useMemo(() => {
  94→        if (!focusedConstellation) return null;
  95→        return new Set([focusedConstellation.star_id_a, focusedConstellation.star_id_b]);
  96→    }, [focusedConstellation]);
  97→
  98→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
  99→    const showTitles = zoom > 0.5;
 100→
 101→    // Sector partitioning for scalable local gravity math.
 102→    const postSectorIndex = useMemo(() => (
 103→        buildSectorIndex(
 104→            postArray,
 105→            (post) => ({
 106→                x: post?.display_x ?? post?.universe_x,
 107→                y: post?.display_y ?? post?.universe_y,
 108→            }),
 109→            SECTOR_SIZE
 110→        )
 111→    ), [postArray]);
 112→
 113→    const centerSectorKey = useMemo(
 114→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
 115→        [centerWorld.x, centerWorld.y]
 116→    );
 117→
 118→    const activeSectorKeys = useMemo(
 119→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
 120→        [centerSectorKey]
 121→    );
 122→
 123→    const activePosts = useMemo(() => {
 124→        if (activeSectorKeys.size === 0) return postArray;
 125→
 126→        const next = [];
 127→        for (const key of activeSectorKeys) {
 128→            const bucket = postSectorIndex.get(key);
 129→            if (bucket?.length) next.push(...bucket);
 130→        }
 131→        return next;
 132→    }, [postArray, postSectorIndex, activeSectorKeys]);
 133→
 134→    const activePostIds = useMemo(() => {
 135→        const ids = new Set();
 136→        for (const post of activePosts) {
 137→            if (post?.id) ids.add(post.id);
 138→        }
 139→        return ids;
 140→    }, [activePosts]);
 141→
 142→    const { centroidByUser } = useMemo(
 143→        () => computeGalaxyCentroids(postArray),
 144→        [postArray]
 145→    );
 146→
 147→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
 148→    const hashGalaxies = useMemo(() => {
 149→        const seen = new Map();
 150→        for (const post of postArray) {
 151→            const uid = post.users?.id ?? post.user_id;
 152→            if (!uid || seen.has(uid)) continue;
 153→            const hash = userHomeCoords(uid);
 154→            seen.set(uid, {
 155→                userId: uid,
 156→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
 157→                x: hash.x,
 158→                y: hash.y,
 159→            });
 160→        }
 161→        return Array.from(seen.values());
 162→    }, [postArray]);
 163→
 164→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
 165→    const centroidTargets = useMemo(() => {
 166→        const map = new Map();
 167→        for (const c of centroids) {
 168→            if (c.galaxy_x != null && c.galaxy_y != null) {
 169→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
 170→            }
 171→        }
 172→        return map;
 173→    }, [centroids]);
 174→
 175→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
 176→    const {
 177→        galaxyPositions,
 178→        starPullOffsets,
 179→        isSettled,
 180→        galaxyEdges: effectiveGalaxyEdges,
 181→        hasEmbeddingGravity,
 182→    } = useCosmicGravity({
 183→        galaxies: hashGalaxies,
 184→        centroidTargets,
 185→        edges: galaxyEdges,
 186→        posts: postArray,
 187→        starPulls,
 188→        centroidByUser,
 189→        activeSectorKeys,
 190→        activePostIds,
 191→        sectorSize: SECTOR_SIZE,
 192→    });
 193→
 194→    // ── Render galaxies = hash galaxies with animated positions ──────
 195→    const galaxies = useMemo(() => {
 196→        return hashGalaxies.map(g => {
 197→            const animated = galaxyPositions.get(g.userId);
 198→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
 199→        });
 200→    }, [hashGalaxies, galaxyPositions]);
 201→
 202→    // Home position for distance tracker — same resolution as auto-focus.
 203→    const homePosition = useMemo(() => {
 204→        if (!userId) return { x: 0, y: 0 };
 205→        const ownGalaxy = galaxies.find((g) => g.userId === userId);
 206→        if (ownGalaxy) return { x: ownGalaxy.x, y: ownGalaxy.y };
 207→        return centroidTargets.get(userId) || ownGalaxyTarget || { x: 0, y: 0 };
 208→    }, [userId, galaxies, centroidTargets, ownGalaxyTarget]);
 209→
 210→    const getComputedStarPosition = useCallback((post) => {
 211→        if (!post) return null;
 212→
 213→        const uid = post.users?.id ?? post.user_id;
 214→        const hashGal = userHomeCoords(uid);
 215→        const animGal = galaxyPositions.get(uid);
 216→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 217→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 218→        const pull = starPullOffsets.get(post.id);
 219→
 220→        const baseX = post.universe_x ?? post.display_x;
 221→        const baseY = post.universe_y ?? post.display_y;
 222→        if (baseX == null || baseY == null) return null;
 223→
 224→        return {
 225→            x: baseX + galDx + (pull?.dx ?? 0),
 226→            y: baseY + galDy + (pull?.dy ?? 0),
 227→        };
 228→    }, [galaxyPositions, starPullOffsets]);
 229→
 230→    // ── Hoisted computedStarPositions for sharing across layers ──────
 231→    const computedStarPositions = useMemo(() => {
 232→        const map = new Map();
 233→        for (const post of postArray) {
 234→            const uid = post.users?.id ?? post.user_id;
 235→            const hashGal = userHomeCoords(uid);
 236→            const animGal = galaxyPositions.get(uid);
 237→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 238→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 239→            const pull = starPullOffsets.get(post.id);
 240→
 241→            const baseX = post.universe_x ?? post.display_x;
 242→            const baseY = post.universe_y ?? post.display_y;
 243→            if (baseX == null || baseY == null) continue;
 244→
 245→            let x = baseX + galDx + (pull?.dx ?? 0);
 246→            let y = baseY + galDy + (pull?.dy ?? 0);
 247→
 248→            map.set(post.id, { x, y });
 249→        }
 250→        return map;
 251→    }, [postArray, galaxyPositions, starPullOffsets]);
 252→
 253→    // ── Constellation pull offsets (spring constraint) ─────────────
 254→    const acceptedConstellations = useMemo(
 255→        () => constellations.filter(c => c.status === 'accepted'),
 256→        [constellations]
 257→    );
 258→
 259→    const constellationPullOffsets = useMemo(
 260→        () => computeConstellationPullOffsets(acceptedConstellations, computedStarPositions),
 261→        [acceptedConstellations, computedStarPositions]
 262→    );
 263→
 264→    // ── Final star positions with constellation pull applied ───────
 265→    const finalStarPositions = useMemo(() => {
 266→        if (constellationPullOffsets.size === 0) return computedStarPositions;
 267→
 268→        const map = new Map(computedStarPositions);
 269→        for (const [postId, offset] of constellationPullOffsets) {
 270→            const pos = map.get(postId);
 271→            if (pos) {
 272→                map.set(postId, {
 273→                    x: pos.x + offset.dx,
 274→                    y: pos.y + offset.dy,
 275→                });
 276→            }
 277→        }
 278→        return map;
 279→    }, [computedStarPositions, constellationPullOffsets]);
 280→
 281→    // ── Constellation chain colors ────────────────────────────────
 282→    const chainColors = useMemo(() => {
 283→        const chains = computeConstellationChains(acceptedConstellations);
 284→        return assignChainColors(chains);
 285→    }, [acceptedConstellations]);
 286→
 287→    // ── Map star ID → constellation chain color for ring indicators ─
 288→    const constellationStarColors = useMemo(() => {
 289→        const map = new Map();
 290→        for (const c of acceptedConstellations) {
 291→            const color = chainColors.get(c.id);
 292→            if (!color) continue;
 293→            if (!map.has(c.star_id_a)) map.set(c.star_id_a, color);
 294→            if (!map.has(c.star_id_b)) map.set(c.star_id_b, color);
 295→        }
 296→        return map;
 297→    }, [acceptedConstellations, chainColors]);
 298→
 299→    // Resolve logged-in user's galaxy target independently from viewport data.
 300→    useEffect(() => {
 301→        if (!userId) return;
 302→        if (ownGalaxyLookupStartedRef.current) return;
 303→
 304→        ownGalaxyLookupStartedRef.current = true;
 305→        let cancelled = false;
 306→
 307→        const resolveOwnGalaxyTarget = async () => {
 308→            try {
 309→                const { data, error } = await supabase
 310→                    .from('galaxy_centroids')
 311→                    .select('galaxy_x, galaxy_y')
 312→                    .eq('user_id', userId)
 313→                    .maybeSingle();
 314→
 315→                if (cancelled) return;
 316→
 317→                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
 318→                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
 319→                    setHasOwnPosts(true);
 320→                    return;
 321→                }
 322→            } catch (err) {
 323→                console.warn('[universe] own centroid lookup failed:', err?.message || err);
 324→            }
 325→
 326→            if (!cancelled) {
 327→                setOwnGalaxyTarget(userHomeCoords(userId));
 328→            }
 329→        };
 330→
 331→        resolveOwnGalaxyTarget();
 332→
 333→        return () => {
 334→            cancelled = true;
 335→        };
 336→    }, [userId]);
 337→
 338→    // One-time wormhole fetch on mount
 339→    useEffect(() => {
 340→        let cancelled = false;
 341→
 342→        const fetchWormholes = async () => {
 343→            try {
 344→                const { data, error } = await supabase.rpc('find_wormhole_pairs', {
 345→                    similarity_threshold: 0.7,
 346→                    min_distance: 0,
 347→                    max_pairs: 30,
 348→                });
 349→                if (cancelled) return;
 350→                if (error) {
 351→                    console.warn('[universe] wormhole fetch error:', error.message);
 352→                    return;
 353→                }
 354→                console.log('[universe] wormhole pairs:', data);
 355→                if (Array.isArray(data) && data.length > 0) {
 356→                    setWormholes(data);
 357→                }
 358→            } catch (err) {
 359→                if (!cancelled) {
 360→                    console.warn('[universe] wormhole fetch failed:', err?.message || err);
 361→                }
 362→            }
 363→        };
 364→
 365→        fetchWormholes();
 366→        return () => { cancelled = true; };
 367→    }, []);
 368→
 369→    // Debounced fetch on camera/zoom change
 370→    useEffect(() => {
 371→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
 372→
 373→        fetchDebounceRef.current = setTimeout(async () => {
 374→            const bounds = getViewportBounds();
 375→            try {
 376→                const result = await getUniversePosts(
 377→                    bounds.minX,
 378→                    bounds.maxX,
 379→                    bounds.minY,
 380→                    bounds.maxY,
 381→                    200
 382→                );
 383→                if (result?.data) {
 384→                    setPosts(prev => {
 385→                        const next = new Map(prev);
 386→                        for (const post of result.data) {
 387→                            next.set(post.id, post);
 388→                        }
 389→                        return next;
 390→                    });
 391→                    if (userId && hasOwnPosts !== true) {
 392→                        const ownsAny = result.data.some(p =>
 393→                            (p.users?.id ?? p.user_id) === userId
 394→                        );
 395→                        if (ownsAny) setHasOwnPosts(true);
 396→                    }
 397→                }
 398→                // Keep server gravity data as fallback when embeddings are absent in payload.
 399→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
 400→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
 401→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
 402→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
 403→
 404→                // Fetch constellations for visible posts
 405→                if (result?.data?.length > 0) {
 406→                    const visibleIds = result.data.map(p => p.id);
 407→                    try {
 408→                        const constResult = await getViewportConstellations(visibleIds);
 409→                        if (constResult?.data) {
 410→                            setConstellations(constResult.data);
 411→                        }
 412→                    } catch (constErr) {
 413→                        console.warn('[universe] constellation fetch failed:', constErr?.message || constErr);
 414→                    }
 415→                }
 416→            } catch (err) {
 417→                console.error('Failed to fetch universe posts:', err);
 418→            } finally {
 419→                if (!initialFetchResolvedRef.current) {
 420→                    initialFetchResolvedRef.current = true;
 421→                    setIsInitialLoading(false);
 422→                }
 423→            }
 424→        }, 400);
 425→
 426→        return () => {
 427→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
 428→        };
 429→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
 430→
 431→    const handleStarClick = useCallback(async (post) => {
 432→        if (isFlying.current) return;
 433→
 434→        // Intercept for link mode
 435→        if (isLinkMode) {
 436→            setLinkModeError(null);
 437→            const result = await handleStarClickInLinkMode(post);
 438→            if (result?.error) {
 439→                setLinkModeError(result.error);
 440→                setTimeout(() => setLinkModeError(null), 3000);
 441→            }
 442→            return;
 443→        }
 444→
 445→        setSelectedPost(post);
 446→        setSelectedGalaxy(null);
 447→        setGalaxyProfile(null);
 448→
 449→        const position = getComputedStarPosition(post);
 450→        if (!position) return;
 451→
 452→        flyTo(position.x, position.y, 1.2, () => {
 453→            setPulsingId(post.id);
 454→            setTimeout(() => setPulsingId(null), 700);
 455→        });
 456→    }, [flyTo, getComputedStarPosition, isFlying, isLinkMode, handleStarClickInLinkMode]);
 457→
 458→    const handleGalaxyClick = useCallback(async (galaxy) => {
 459→        if (isFlying.current) return;
 460→        setSelectedGalaxy(galaxy);
 461→        setSelectedPost(null);
 462→        setGalaxyProfile(null);
 463→        flyTo(galaxy.x, galaxy.y, 0.8);
 464→
 465→        try {
 466→            const data = await getUserData(galaxy.userId);
 467→            const profile = data?.userData?.[0] || null;
 468→            setGalaxyProfile(profile);
 469→        } catch (err) {
 470→            console.error('Failed to fetch galaxy profile:', err);
 471→        }
 472→    }, [flyTo, isFlying]);
 473→
 474→    const handleReadPost = useCallback(() => {
 475→        if (!selectedPost) return;
 476→        navigate(`/home/post/${selectedPost.id}`);
 477→    }, [selectedPost, navigate]);
 478→
 479→    const handleMinimapNavigate = useCallback((worldX, worldY, mode = 'fly') => {
 480→        if (mode === 'drag') {
 481→            jumpTo(worldX, worldY);
 482→            return;
 483→        }
 484→        flyTo(worldX, worldY, zoom);
 485→    }, [flyTo, jumpTo, zoom]);
 486→
 487→    // Enrich wormhole positions with live gravity-computed post coords
 488→    const enrichedWormholes = useMemo(() => {
 489→        return wormholes.map(wh => {
 490→            const postA = posts.get(wh.post_a);
 491→            const postB = posts.get(wh.post_b);
 492→            const posA = postA ? getComputedStarPosition(postA) : null;
 493→            const posB = postB ? getComputedStarPosition(postB) : null;
 494→            return {
 495→                ...wh,
 496→                a_x: posA?.x ?? wh.a_x,
 497→                a_y: posA?.y ?? wh.a_y,
 498→                b_x: posB?.x ?? wh.b_x,
 499→                b_y: posB?.y ?? wh.b_y,
 500→            };
 501→        });
 502→    }, [wormholes, posts, getComputedStarPosition]);
 503→
 504→    // Find wormhole connection for a given post (if any)
 505→    const getWormholeForPost = useCallback((postId) => {
 506→        if (!postId || enrichedWormholes.length === 0) return null;
 507→        for (const wh of enrichedWormholes) {
 508→            if (wh.post_a === postId) return { wormhole: wh, side: 'a', targetTitle: wh.b_title };
 509→            if (wh.post_b === postId) return { wormhole: wh, side: 'b', targetTitle: wh.a_title };
 510→        }
 511→        return null;
 512→    }, [enrichedWormholes]);
 513→
 514→    const handleWormholeTravel = useCallback(() => {
 515→        if (!selectedPost || isFlying.current) return;
 516→        const match = getWormholeForPost(selectedPost.id);
 517→        if (!match) return;
 518→        const { wormhole, side } = match;
 519→        const targetX = side === 'a' ? wormhole.b_x : wormhole.a_x;
 520→        const targetY = side === 'a' ? wormhole.b_y : wormhole.a_y;
 521→        setSelectedPost(null);
 522→        setIsWarping(true);
 523→        flyTo(targetX, targetY, zoom, () => setIsWarping(false));
 524→    }, [selectedPost, getWormholeForPost, flyTo, isFlying, zoom]);
 525→
 526→    // Find constellation links for a given post
 527→    const getConstellationLinksForPost = useCallback((postId) => {
 528→        if (!postId || acceptedConstellations.length === 0) return [];
 529→        const links = [];
 530→        for (const c of acceptedConstellations) {
 531→            if (c.star_id_a === postId) {
 532→                links.push({ constellation: c, targetStarId: c.star_id_b, targetTitle: c.b_title || 'Unnamed Star', label: c.label });
 533→            } else if (c.star_id_b === postId) {
 534→                links.push({ constellation: c, targetStarId: c.star_id_a, targetTitle: c.a_title || 'Unnamed Star', label: c.label });
 535→            }
 536→        }
 537→        return links;
 538→    }, [acceptedConstellations]);
 539→
 540→    const handleConstellationTravel = useCallback((targetStarId, constellation) => {
 541→        if (isFlying.current) return;
 542→        // Try live computed position first
 543→        let targetPos = finalStarPositions.get(targetStarId);
 544→        // Fallback to raw RPC positions from the constellation record
 545→        if (!targetPos && constellation) {
 546→            if (constellation.star_id_a === targetStarId && constellation.a_universe_x != null) {
 547→                targetPos = { x: constellation.a_universe_x, y: constellation.a_universe_y };
 548→            } else if (constellation.star_id_b === targetStarId && constellation.b_universe_x != null) {
 549→                targetPos = { x: constellation.b_universe_x, y: constellation.b_universe_y };
 550→            }
 551→        }
 552→        if (!targetPos) return;
 553→        setSelectedPost(null);
 554→        flyTo(targetPos.x, targetPos.y, zoom);
 555→    }, [finalStarPositions, flyTo, isFlying, zoom]);
 556→
 557→    const handleConstellationFocus = useCallback((link) => {
 558→        if (isLinkMode) return;
 559→        setFocusedConstellation(link);
 560→        setSelectedPost(null);
 561→    }, [isLinkMode]);
 562→
 563→    const handleDismissFocus = useCallback(() => {
