    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    color: #e0e0e0;
    font-size: 14px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.rocketExitBtn:hover {
    background: rgba(255, 255, 255, 0.12);
    border-color: rgba(255, 255, 255, 0.2);
}

.rocketSpeedBar {
    position: absolute;
    bottom: 24px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 10px 18px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    pointer-events: none;
}

.rocketSpeedLabel {
    font-size: 11px;
    font-family: monospace;
    color: rgba(255, 255, 255, 0.4);
    letter-spacing: 0.05em;
}

.rocketSpeedTrack {
    width: 160px;
    height: 6px;
    background: rgba(255, 255, 255, 0.08);
    border-radius: 3px;
    overflow: hidden;
}

.rocketSpeedFill {
    height: 100%;
    background: linear-gradient(90deg, #5f92ff, #ff5fa2);
    border-radius: 3px;
    transition: width 0.1s linear;
}

.rocketSpeedValue {
    font-size: 11px;
    font-family: monospace;
    color: rgba(255, 255, 255, 0.5);
    min-width: 32px;
    text-align: right;
}

.rocketTarget {
    position: absolute;
    bottom: 80px;
    left: 50%;
    transform: translateX(-50%);
    text-align: center;
    pointer-events: none;
}

.rocketTargetTitle {
    font-size: 15px;
    font-weight: 700;
    color: rgba(255, 255, 255, 0.9);
    text-shadow: 0 0 12px rgba(0, 255, 255, 0.3);
    margin-bottom: 2px;
    white-space: nowrap;
    max-width: 320px;
    overflow: hidden;
    text-overflow: ellipsis;
}

.rocketTargetAuthor {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.45);
    margin-bottom: 6px;
}

.rocketTargetPrompt {
    font-size: 12px;
    font-family: monospace;
    color: rgba(0, 255, 255, 0.7);
    animation: rocketPromptPulse 1.5s ease-in-out infinite;
}

.rocketControls {
    position: absolute;
    bottom: 24px;
    right: 16px;
    display: flex;
    flex-direction: column;
    gap: 4px;
    pointer-events: none;
}

.rocketControls span {
    font-size: 11px;
    font-family: monospace;
    color: rgba(255, 255, 255, 0.25);
}

.galaxyPreviewExploreBtn {
    display: inline-block;
    margin-top: 8px;
    padding: 8px 22px;
    background: rgba(255, 160, 50, 0.15);
    border: 1px solid rgba(255, 160, 50, 0.4);
    border-radius: 10px;
    color: #ffa032;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.galaxyPreviewExploreBtn:hover {
    background: rgba(255, 160, 50, 0.25);
    border-color: rgba(255, 160, 50, 0.6);
}

.rocketWarpIn {
    position: absolute;
    inset: 0;
    z-index: 1030;
    pointer-events: none;
    background: radial-gradient(
        ellipse at center,
        rgba(95, 146, 255, 0.35) 0%,
        rgba(0, 0, 0, 0.9) 70%,
        rgba(0, 0, 0, 1) 100%
    );
    animation: rocketWarpInAnim 0.8s ease-out forwards;
}

@keyframes rocketWarpInAnim {
    0% {
        opacity: 0;
        transform: scale(1);
    }
    40% {
        opacity: 1;
    }
    100% {
        opacity: 0;
        transform: scale(3);
    }
}

.rocketPitch {
    position: absolute;
    top: 16px;
    right: 16px;
    font-size: 13px;
    font-family: monospace;
    color: rgba(255, 255, 255, 0.4);
    pointer-events: none;
}

@keyframes rocketPromptPulse {
    0%, 100% {
        opacity: 0.5;
    }
    50% {
        opacity: 1;
    }
}

.rocketTargetDistance {
    font-size: 11px;
    font-family: monospace;
    color: rgba(0, 255, 255, 0.6);
    margin-bottom: 4px;
}

.rocketTargetDocking {
    font-size: 13px;
    font-family: monospace;
    font-weight: 700;
    color: rgba(255, 160, 50, 0.95);
    text-shadow: 0 0 12px rgba(255, 160, 50, 0.5);
    animation: rocketDockingPulse 0.4s ease-in-out infinite alternate;
}

@keyframes rocketDockingPulse {
    0% { opacity: 0.7; transform: scale(1); }
    100% { opacity: 1; transform: scale(1.05); }
}

/* Reverse warp overlay (returning from post) */
.reverseWarp {
    position: absolute;
    inset: 0;
    z-index: 1030;
    pointer-events: none;
    background: radial-gradient(
        ellipse at center,
        rgba(255, 255, 255, 0.9) 0%,
        rgba(150, 180, 255, 0.5) 40%,
        rgba(10, 14, 26, 0.95) 100%
    );
    animation: reverseWarpFade 600ms ease-out forwards;
}

@keyframes reverseWarpFade {
    0% { opacity: 1; }
    100% { opacity: 0; }
}

/* ── Touch Controls (Mobile) ──────────────────────────────────── */

.joystickRing {
    position: absolute;
    bottom: 80px;
    left: 30px;
    width: 100px;
    height: 100px;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.04);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border: 1px solid rgba(255, 255, 255, 0.12);
    display: flex;
    align-items: center;
    justify-content: center;
    touch-action: none;
    user-select: none;
    pointer-events: auto;
    z-index: 1025;
}

.joystickKnob {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.15);
    border: 1px solid rgba(255, 255, 255, 0.25);
    transition: transform 60ms ease-out;
    pointer-events: none;
}

.throttleArea {
    position: absolute;
    bottom: 80px;
    right: 30px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 14px;
    touch-action: none;
    user-select: none;
    pointer-events: auto;
    z-index: 1025;
}

.thrustBtn {
    width: 72px;
    height: 72px;
    border-radius: 50%;
    background: rgba(255, 160, 50, 0.12);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border: 2px solid rgba(255, 160, 50, 0.4);
    color: rgba(255, 160, 50, 0.9);
    font-size: 11px;
    font-weight: 700;
    font-family: monospace;
    letter-spacing: 0.05em;
    cursor: pointer;
    touch-action: none;
    user-select: none;
    transition: background 0.15s, border-color 0.15s;
}

.thrustBtn:active {
    background: rgba(255, 160, 50, 0.3);
    border-color: rgba(255, 160, 50, 0.7);
}

.dockBtn {
    width: 56px;
    height: 56px;
    border-radius: 50%;
    background: rgba(0, 255, 255, 0.08);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border: 2px solid rgba(0, 255, 255, 0.3);
    color: rgba(0, 255, 255, 0.85);
    font-size: 10px;
    font-weight: 700;
    font-family: monospace;
    letter-spacing: 0.05em;
    cursor: pointer;
    touch-action: none;
    user-select: none;
    transition: background 0.15s, border-color 0.15s;
}

.dockBtn:active {
    background: rgba(0, 255, 255, 0.22);
    border-color: rgba(0, 255, 255, 0.6);
}
